__CPROVER_requires(btype != 0 ==> __CPROVER_is_fresh(lz77->d_counts,
    (ZOPFLI_NUM_D * ((lz77->size - 1) / ZOPFLI_NUM_D) + ZOPFLI_NUM_D) * sizeof(size_t)))
