__CPROVER_requires(btype != 0 ==> __CPROVER_is_fresh(lz77->d_symbol, lz77->size * sizeof(unsigned short)))
__CPROVER_requires(btype != 0 ==> __CPROVER_is_fresh(lz77->dists, lz77->size * sizeof(unsigned short)))
