    size_t lli; (lli < lz77->size) ==> lz77->ll_symbol[lli] < ZOPFLI_NUM_LL })
__CPROVER_requires(btype != 0 ==> __CPROVER_forall {
    size_t dsi; (dsi < lz77->size) ==> lz77->d_symbol[dsi] < ZOPFLI_NUM_D })
